// src/commands/site/utils/ProjectSyncer.ts
class ProjectSyncer {
  client;
  constructor(client) {
    this.client = client;
  }
  async fetchManifest(projectId) {
    const response = await this.client.callTool("list_screens", {
      projectId
    });
    return response.screens || [];
  }
  async fetchContent(url) {
    const maxRetries = 4;
    for (let attempt = 0;attempt <= maxRetries; attempt++) {
      const response = await fetch(url);
      if (response.ok)
        return await response.text();
      if (response.status === 429 && attempt < maxRetries) {
        const backoff = Math.min(1000 * 2 ** attempt, 8000);
        await new Promise((r) => setTimeout(r, backoff));
        continue;
      }
      throw new Error(`Failed to fetch content: ${response.statusText}`);
    }
    throw new Error(`Failed to fetch content after ${maxRetries + 1} attempts`);
  }
}

